const { SQSClient, ReceiveMessageCommand, DeleteMessageCommand } = require("@aws-sdk/client-sqs");
const { DynamoDBClient, UpdateItemCommand } = require("@aws-sdk/client-dynamodb");
const { marshall, unmarshall } = require("@aws-sdk/util-dynamodb");
const { SecretsManagerClient, GetSecretValueCommand } = require("@aws-sdk/client-secrets-manager");

const sqs = new SQSClient({ region: process.env.AWS_REGION });
const dynamo = new DynamoDBClient({ region: process.env.AWS_REGION });
const secretsManager = new SecretsManagerClient({ region: process.env.AWS_REGION });

const QUEUE_URL = process.env.PAYMENT_QUEUE_URL;
const SECRET_ARN = process.env.DATABASE_SECRET_ARN;
const TABLE_NAME = process.env.TRANSACTION_TABLE_NAME;

let dbCredentials = null;

async function getDatabaseCredentials() {
  if (dbCredentials) return dbCredentials;
  
  const command = new GetSecretValueCommand({
    SecretId: SECRET_ARN
  });
  
  const response = await secretsManager.send(command);
  dbCredentials = JSON.parse(response.SecretString);
  return dbCredentials;
}

function validateTransactionData(data) {
  if (!data || typeof data !== 'object') {
    throw new Error('Invalid transaction data');
  }
  
  const requiredFields = ['transactionId', 'amount', 'accountId', 'status'];
  for (const field of requiredFields) {
    if (!(field in data)) {
      throw new Error(`Missing required field: ${field}`);
    }
  }
  
  if (typeof data.amount !== 'number' || data.amount <= 0) {
    throw new Error('Invalid amount');
  }
  
  if (typeof data.accountId !== 'string' || data.accountId.length === 0) {
    throw new Error('Invalid account ID');
  }
  
  if (typeof data.transactionId !== 'string' || data.transactionId.length === 0) {
    throw new Error('Invalid transaction ID');
  }
  
  const validStatuses = ['pending', 'completed', 'failed', 'refunded'];
  if (!validStatuses.includes(data.status)) {
    throw new Error('Invalid status');
  }
  
  return true;
}

async function processTransaction(message) {
  const data = JSON.parse(message.Body);
  validateTransactionData(data);
  
  const credentials = await getDatabaseCredentials();
  
  const updateCommand = new UpdateItemCommand({
    TableName: TABLE_NAME,
    Key: {
      transactionId: data.transactionId
    },
    UpdateExpression: "SET #status = :status, #amount = :amount, #updatedAt = :updatedAt",
    ExpressionAttributeNames: {
      "#status": "status",
      "#amount": "amount",
      "#updatedAt": "updatedAt"
    },
    ExpressionAttributeValues: {
      ":status": data.status,
      ":amount": data.amount,
      ":updatedAt": new Date().toISOString()
    },
    ReturnValues: "UPDATED_NEW"
  });
  
  try {
    await dynamo.send(updateCommand);
    console.log(`Successfully processed transaction: ${data.transactionId}`);
  } catch (error) {
    console.error(`Failed to process transaction ${data.transactionId}:`, error);
    throw error;
  }
}

async function consumeMessages() {
  const command = new ReceiveMessageCommand({
    QueueUrl: QUEUE_URL,
    MaxNumberOfMessages: 10,
    VisibilityTimeout: 30,
    WaitTimeSeconds: 20
  });
  
  try {
    const response = await sqs.send(command);
    
    if (response.Messages && response.Messages.length > 0) {
      const processPromises = response.Messages.map(async (message) => {
        try {
          await processTransaction(message);
          
          const deleteCommand = new DeleteMessageCommand({
            QueueUrl: QUEUE_URL,
            ReceiptHandle: message.ReceiptHandle
          });
          
          await sqs.send(deleteCommand);
        } catch (error) {
          console.error('Error processing message:', error);
        }
      });
      
      await Promise.all(processPromises);
    }
  } catch (error) {
    console.error('Error consuming messages:', error);
  }
}

async function startConsumer() {
  console.log('Starting payment transaction consumer...');
  
  while (true) {
    try {
      await consumeMessages();
      await new Promise(resolve => setTimeout(resolve, 1000));
    } catch (error) {
      console.error('Consumer error:', error);
      await new Promise(resolve => setTimeout(resolve, 5000));
    }
  }
}

startConsumer().catch(console.error);